import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const spanRole = {
    name: 'span',
    options: { ...commonRoleOptions('span') },
    body: {
        type: 'myst',
    },
    run(data) {
        const node = { type: 'span' };
        if (data.body) {
            node.children = data.body;
        }
        addCommonRoleOptions(data, node);
        return [node];
    },
};
